let state=loadState();
let cleanup=()=>{};
function id(){return (crypto.randomUUID?crypto.randomUUID():Math.random().toString(36).slice(2)+Date.now())}
function dateISO(offset=0){const d=new Date();d.setDate(d.getDate()+offset);return d.toISOString().slice(0,10)}
function makeWorkout(name,daysAgo,totalVolume,totalSets){return{id:id(),name,startedAt:new Date(Date.now()-daysAgo*86400000).toISOString(),totalVolume,totalSets,sets:[]}}
function makeFoodLog(foodId,mealCategory,servings){const f=foods.find(x=>x.id===foodId);return{id:id(),foodId,foodName:f.name,date:dateISO(),mealCategory,servings,calories:Math.round(f.calories*servings),protein:Math.round(f.protein*servings),carbs:Math.round(f.carbs*servings),fat:Math.round(f.fat*servings)}}
function loadState(){try{const saved=JSON.parse(localStorage.getItem(STORE_KEY)||"null");return saved?merge(defaultState,saved):structuredClone(defaultState)}catch{return structuredClone(defaultState)}}
function merge(base,saved){return {...structuredClone(base),...saved,settings:{...base.settings,...(saved.settings||{})}}}
function save(){localStorage.setItem(STORE_KEY,JSON.stringify(state))}
function esc(v){return String(v??"").replace(/[&<>'"]/g,c=>({"&":"&amp;","<":"&lt;",">":"&gt;","'":"&#39;","\"":"&quot;"}[c]))}
function money(n){return Math.round(n||0).toLocaleString()}
function currentPath(){const h=location.hash.replace(/^#/,"");return h||"/"}
function go(path){location.hash=path}
function todayLogs(){return state.nutritionLogs.filter(l=>l.date===dateISO())}
function summary(){const logs=todayLogs();const calories=logs.reduce((s,l)=>s+l.calories,0);const protein=logs.reduce((s,l)=>s+l.protein,0);const completed=state.habitLogs.filter(l=>l.date===dateISO()&&l.completed).length;const volumes=weeklyVolume();const sleep=7.5;const readiness=Math.min(99,Math.round((sleep/9)*40+82*.3+Math.min(state.workouts.length,7)*4));return{todayCalories:calories,todayProtein:protein,calorieGoal:state.settings.trainingCalories,currentStreak:workoutStreak(),readinessScore:readiness,habitConsistency:habitRate(),habitsCompletedToday:completed,totalHabits:state.habits.length,weeklyVolume:volumes}}
function weeklyVolume(){return Array.from({length:7},(_,i)=>{const offset=i-6;const d=dateISO(offset);const volume=state.workouts.filter(w=>w.startedAt.slice(0,10)===d).reduce((s,w)=>s+(w.totalVolume||0),0);return{date:d,volume}})}
function workoutStreak(){let streak=0;for(let i=0;i<365;i++){const d=dateISO(-i);const has=state.workouts.some(w=>w.startedAt.slice(0,10)===d);if(has)streak++;else if(i>0)break}return streak}
function habitRate(){const total=Math.max(1,state.habits.length*30);let done=0;for(let i=0;i<30;i++){const d=dateISO(-i);done+=state.habitLogs.filter(l=>l.date===d&&l.completed).length}return Math.min(1,done/total||.85)}
function shell(){const path=currentPath();document.getElementById("app").innerHTML=`<div class="app-shell"><aside class="sidebar"><button class="logo" data-go="/"><span>O</span><small>OMNI</small></button><nav class="nav">${navItems.map(n=>navButton(n,path)).join("")}</nav><div class="nav-bottom">${navButton({path:"/settings",label:"Settings",icon:icons.settings},path)}</div></aside><main class="main"><div id="view"></div></main><nav class="mobile-nav">${navItems.map(n=>navButton(n,path)).join("")}</nav>${path!=="/ai"?'<button class="fab" data-go="/ai">'+icons.ai+'<span>Coach</span></button>':""}</div>`;document.querySelectorAll("[data-go]").forEach(b=>b.addEventListener("click",()=>go(b.dataset.go)));renderView(path)}
function navButton(n,path){const active=path===n.path||(n.path!=="/"&&path.startsWith(n.path));return`<button class="nav-btn ${active?"active":""}" data-go="${n.path}" title="${n.label}"><span class="nav-icon">${n.icon}</span><span class="nav-text">${n.label}</span><span class="nav-tip">${n.label}</span></button>`}
function renderView(path){cleanup();cleanup=()=>{};if(path.startsWith("/workouts/active"))return renderActiveWorkout();if(path==="/workouts")return renderWorkouts();if(path==="/nutrition")return renderNutrition();if(path==="/recovery")return renderRecovery();if(path==="/analytics")return renderAnalytics();if(path==="/ai")return renderAI();if(path==="/settings")return renderSettings();return renderDashboard()}
function header(eyebrow,title,right=""){return`<header class="page-header"><div><p class="eyebrow">${eyebrow}</p><h1 class="display">${title}</h1></div>${right}</header>`}
function barChart(data){const max=Math.max(...data.map(d=>d.volume),1);const labels=["MON","TUE","WED","THU","FRI","SAT","SUN"];const today=(new Date().getDay()+6)%7;return`<div class="bar-chart">${data.map((d,i)=>`<div class="bar-wrap"><div class="bar ${i===today?"today":""}" title="${money(d.volume)} lbs" style="height:${Math.max(4,d.volume/max*100)}%"></div><div class="bar-label">${labels[i]}</div></div>`).join("")}</div>`}
function muscleBars(items){return`<div class="stack">${items.map(x=>`<div><div class="row"><span class="stat-label">${x.label}</span><strong style="color:${x.color}">${x.pct}%</strong></div><div class="progress mini-progress"><span style="--w:${x.pct}%;background:${x.color};color:${x.color}"></span></div></div>`).join("")}</div>`}
function habitDots(rate){const filled=Math.round(50*rate);return`<div class="habit-grid">${Array.from({length:50},(_,i)=>`<span class="dot ${i<filled?"on":""}"></span>`).join("")}</div>`}
function muscleSvg(){return`<svg class="muscle-svg" viewBox="0 0 120 220" fill="none"><ellipse cx="60" cy="22" rx="14" ry="17" fill="rgba(255,255,255,.08)" stroke="rgba(255,255,255,.15)"/><rect x="53" y="37" width="14" height="10" rx="3" fill="rgba(255,255,255,.07)"/><path d="M35 47 Q30 55 30 75 L30 120 Q30 130 45 132 L75 132 Q90 130 90 120 L90 75 Q90 55 85 47 Z" fill="rgba(255,255,255,.04)" stroke="rgba(255,255,255,.12)"/><ellipse cx="48" cy="65" rx="14" ry="10" fill="rgba(255,120,0,.55)" filter="blur(5px)"/><ellipse cx="72" cy="65" rx="14" ry="10" fill="rgba(255,120,0,.55)" filter="blur(5px)"/><ellipse cx="31" cy="55" rx="9" ry="8" fill="rgba(255,120,0,.5)" filter="blur(4px)"/><ellipse cx="89" cy="55" rx="9" ry="8" fill="rgba(255,120,0,.5)" filter="blur(4px)"/><path d="M24 62 Q16 72 14 95 Q18 102 22 95 Q26 72 32 65 Z" fill="rgba(255,255,255,.05)" stroke="rgba(255,255,255,.1)"/><path d="M96 62 Q104 72 106 95 Q102 102 98 95 Q94 72 88 65 Z" fill="rgba(255,255,255,.05)" stroke="rgba(255,255,255,.1)"/><path d="M38 130 Q38 145 60 148 Q82 145 82 130 Z" fill="rgba(255,255,255,.05)" stroke="rgba(255,255,255,.1)"/><rect x="36" y="148" width="20" height="40" rx="8" fill="rgba(255,255,255,.05)" stroke="rgba(255,255,255,.1)"/><rect x="64" y="148" width="20" height="40" rx="8" fill="rgba(255,255,255,.05)" stroke="rgba(255,255,255,.1)"/><rect x="38" y="192" width="16" height="26" rx="7" fill="rgba(255,255,255,.04)"/><rect x="66" y="192" width="16" height="26" rx="7" fill="rgba(255,255,255,.04)"/>${[80,92,104].map(y=>`<rect x="50" y="${y}" width="8" height="8" rx="2" fill="rgba(255,255,255,.08)"/><rect x="62" y="${y}" width="8" height="8" rx="2" fill="rgba(255,255,255,.08)"/>`).join("")}</svg>`}
function renderDashboard(){const s=summary();const pct=Math.min(100,s.todayCalories/s.calorieGoal*100);view().innerHTML=`<section class="page">${header("God-mode dashboard","Project OMNI",`<div class="row"><div><p class="stat-label">Sync Status</p><p class="teal glow-text tiny"><b>LOCAL_OFFLINE</b></p></div><div><p class="stat-label">Current Streak</p><p class="orange glow-text"><b>${s.currentStreak} DAYS</b></p></div></div>`)}<div class="grid grid-3"><div class="card"><p class="stat-label">Readiness Score</p><div><span class="readiness">${s.readinessScore}</span><span class="muted" style="font-size:32px;font-weight:900">%</span></div><p class="small muted">Central nervous system recovered. Volume ceiling increased by <b class="white">12%</b> for today's push session.</p><div class="row" style="margin-top:14px">${[88,72,95,60].map(v=>`<div class="progress mini-progress" style="flex:1"><span style="--w:${v}%;background:${v>80?TEAL:v>60?PURPLE:ORANGE}"></span></div>`).join("")}</div></div><div class="card"><div class="row"><div><p class="stat-label">Weekly Training Volume</p><p class="tiny muted">LBS / WEEK</p></div><span class="badge">Today</span></div>${barChart(s.weeklyVolume)}</div><div class="card"><p class="stat-label">Muscle Saturation</p>${muscleSvg()}</div><div class="card-teal"><p class="stat-label teal">AI Super-Coach Insight</p><p style="margin-top:24px;line-height:1.55"><i>Your <b>sleep quality (+14% vs avg)</b> correlates with a <b class="teal">4kg projected increase</b> in your Bench Press 1RM for today's session.</i></p></div><div class="card"><p class="stat-label" style="margin-bottom:18px">Habit Consistency</p>${habitDots(s.habitConsistency)}<div class="row" style="margin-top:16px;padding-top:14px;border-top:1px solid rgba(255,255,255,.06)"><span class="stat-label">Last 30 Days</span><div><b>${(s.habitConsistency*100).toFixed(1)}%</b> <b class="teal small">+2.1%</b></div></div></div><div class="card">${muscleBars([{label:"CHEST (PEC MAJOR)",pct:88,color:ORANGE},{label:"DELTOIDS",pct:34,color:TEAL},{label:"TRICEPS",pct:72,color:TEAL},{label:"QUADRICEPS",pct:91,color:ORANGE},{label:"LATS",pct:55,color:TEAL}])}</div></div><div class="card row" style="margin-top:16px"><div><p class="stat-label">Daily Calories</p><p><b style="font-size:26px">${money(s.todayCalories)}</b> <span class="muted">/ ${money(s.calorieGoal)} kcal</span></p></div><div class="progress" style="flex:1"><span style="--w:${pct}%;background:${TEAL}"></span></div><div><p class="stat-label">Remaining</p><b class="teal">${money(Math.max(0,s.calorieGoal-s.todayCalories))}</b></div></div></section>`}
function exerciseByName(name){return exerciseLibrary.find(e=>e.name===name)||exerciseLibrary[0]}
  function routineItems(r){return (r.exercises||[]).map(x=>typeof x==="string"?{name:x,sets:exerciseByName(x).defaultSets,reps:exerciseByName(x).defaultReps,rest:exerciseByName(x).defaultRest,tempo:exerciseByName(x).tempo,type:"Straight sets",rpe:"RPE 8"}:x)}
  function workoutVolume(){return state.workouts.reduce((a,w)=>a+(w.totalVolume||0),0)}
  function muscleCounts(){const m={};state.workouts.flatMap(w=>w.sets||[]).forEach(set=>{const ex=exerciseByName(set.exerciseName);m[ex.muscle]=(m[ex.muscle]||0)+1});return m}
  function stickFigure(type="push"){return `<div class="stick-stage ${type}"><div class="floor"></div><div class="stick"><span class="head"></span><span class="torso"></span><span class="arm left"></span><span class="arm right"></span><span class="leg left"></span><span class="leg right"></span><span class="load"></span></div><div class="motion-rings"><i></i><i></i><i></i></div></div>`}
  function exerciseCard(ex,compact=false){const cached=state.exerciseGuides?.[ex.id];return `<article class="exercise-card"><div class="exercise-top"><div><p class="stat-label">${esc(ex.pattern)} • ${esc(ex.equipment)}</p><h3>${esc(ex.name)}</h3></div><span class="pill ${cached?'green':'teal'}">${cached?'Offline saved':'Guide ready'}</span></div>${stickFigure(ex.animation)}<div class="chip-row"><span>${esc(ex.muscle)}</span><span>${esc(ex.level)}</span><span>${esc(ex.defaultSets)} sets</span><span>${esc(ex.defaultReps)}</span><span>${Math.round(ex.defaultRest)}s rest</span></div>${compact?'':`<p class="small muted">${esc(ex.progression)}</p><div class="guide-grid"><div><b>Form cues</b>${ex.cues.map(c=>`<p>• ${esc(c)}</p>`).join("")}</div><div><b>Avoid</b>${ex.mistakes.map(c=>`<p>• ${esc(c)}</p>`).join("")}</div></div>`}<div class="exercise-actions"><button class="btn btn-teal" data-add-exercise="${ex.id}">Add</button><button class="btn" data-cache-guide="${ex.id}">${cached?'Refresh guide':'Save offline'}</button><button class="btn" data-customize-ex="${ex.id}">Customize</button></div></article>`}
  async function cacheExerciseGuide(ex){state.exerciseGuides=state.exerciseGuides||{};let ai=null;if(state.settings.apiKey&&navigator.onLine){try{const res=await fetch("https://api.openai.com/v1/chat/completions",{method:"POST",headers:{"Content-Type":"application/json","Authorization":`Bearer ${state.settings.apiKey}`},body:JSON.stringify({model:state.settings.model||"gpt-4o",messages:[{role:"system",content:"Create concise exercise coaching notes with setup, execution, cues, common mistakes, regressions and progressions."},{role:"user",content:`Exercise: ${ex.name}. Equipment: ${ex.equipment}. Muscle: ${ex.muscle}.`}],temperature:.35})});if(res.ok){const data=await res.json();ai=data.choices?.[0]?.message?.content||null}}catch{}}state.exerciseGuides[ex.id]={...ex,downloadedAt:new Date().toISOString(),aiNotes:ai||"Offline guide cached from OMNI's built-in exercise library.",stickModel:ex.animation};save()}
  function renderWorkouts(){const recent=[...state.workouts].sort((a,b)=>new Date(b.startedAt)-new Date(a.startedAt)).slice(0,6);const settings=state.workoutSettings||{};const counts=muscleCounts();const topMuscle=Object.entries(counts).sort((a,b)=>b[1]-a[1])[0]?.[0]||"Chest";view().innerHTML=`<section class="page workouts-page">${header("Training hub","Workouts",`<div class="row"><span class="badge">${exercises.length} offline exercises</span><span class="badge green">${state.routines.length} plans</span></div>`)}<div class="workout-hero"><div class="hero-copy"><p class="eyebrow">Offline professional workout builder</p><h2>Plan, customize, learn form, start sessions, and save every detail locally.</h2><p class="muted">Routines, exercise library, rest timers, RPE, tempo, progression, history, templates, posture guides and offline cache.</p><div class="hero-actions"><button class="btn btn-teal" id="startBlank">${icons.play} Start blank</button><button class="btn" id="openBuilder">${icons.plus} New routine</button><button class="btn" id="addCustomExercise">Custom exercise</button></div></div><div class="hero-figure">${stickFigure("squat")}<div class="mini-stats"><b>${money(workoutVolume())}</b><span>Total volume</span></div></div></div><div class="grid grid-4 workout-metrics"><div class="card"><p class="stat-label">Workout Streak</p><b>${workoutStreak()}</b><span>days</span></div><div class="card"><p class="stat-label">Total Sessions</p><b>${state.workouts.length}</b><span>logged</span></div><div class="card"><p class="stat-label">Top Muscle</p><b>${topMuscle}</b><span>recent focus</span></div><div class="card"><p class="stat-label">Guide Cache</p><b>${Object.keys(state.exerciseGuides||{}).length}</b><span>offline guides</span></div></div><div class="tabs-row" id="workoutTabs"><button class="tab active" data-panel="routines">Routines</button><button class="tab" data-panel="library">Exercise Library</button><button class="tab" data-panel="builder">Plan Builder</button><button class="tab" data-panel="options">Options</button><button class="tab" data-panel="history">History</button></div><div id="workoutPanel"></div></section>`;const panel=document.getElementById("workoutPanel");function drawPanel(name="routines"){document.querySelectorAll("#workoutTabs .tab").forEach(t=>t.classList.toggle("active",t.dataset.panel===name));if(name==="routines")panel.innerHTML=`<section class="panel-block"><div class="section-head"><div><p class="stat-label">My Routines</p><h2>Saved training plans</h2></div><span class="tiny muted">Start loads the whole plan into a live session</span></div><div class="grid grid-3">${state.routines.map(r=>{const items=routineItems(r);return `<article class="routine-card"><div class="row"><div class="icon-box">${icons.workouts}</div><span class="pill">${items.length} exercises</span></div><h3>${esc(r.name)}</h3><p class="small muted">${esc(r.description||"Custom routine")}</p><div class="routine-list">${items.slice(0,5).map(i=>`<div><span>${esc(i.name)}</span><b>${esc(i.sets||3)}×${esc(i.reps||"8-12")}</b></div>`).join("")}</div><div class="exercise-actions"><button class="btn btn-teal" data-start-routine="${r.id}">Start</button><button class="btn" data-edit-routine="${r.id}">Edit</button><button class="btn btn-danger" data-delete-routine="${r.id}">Delete</button></div></article>`}).join("")}</div><div class="section-head"><div><p class="stat-label">Templates</p><h2>One-tap program starters</h2></div></div><div class="grid grid-4">${workoutTemplates.map((t,i)=>`<button class="template-card" data-template="${i}"><b>${esc(t.name)}</b><span>${esc(t.goal)}</span><small>${t.days} days • ${t.exercises.length} movements</small></button>`).join("")}</div></section>`;if(name==="library")panel.innerHTML=`<section class="panel-block"><div class="library-tools"><input class="input" id="exerciseSearch" placeholder="Search exercise, muscle, equipment, cue..."><select class="input" id="muscleFilter"><option>All muscles</option>${[...new Set(exerciseLibrary.map(e=>e.muscle))].map(m=>`<option>${m}</option>`).join("")}</select><select class="input" id="equipmentFilter"><option>All equipment</option>${[...new Set(exerciseLibrary.map(e=>e.equipment))].map(m=>`<option>${m}</option>`).join("")}</select><select class="input" id="levelFilter"><option>All levels</option>${[...new Set(exerciseLibrary.map(e=>e.level))].map(m=>`<option>${m}</option>`).join("")}</select></div><div class="exercise-library" id="exerciseLibrary"></div></section>`;if(name==="builder")panel.innerHTML=`<section class="panel-block"><div class="grid grid-3"><div class="card"><p class="stat-label white">Routine identity</p><div class="field"><label class="stat-label">Name</label><input class="input" id="routineName" value="Custom Strength Plan"></div><div class="field"><label class="stat-label">Goal / notes</label><textarea class="input" id="routineDesc" rows="4">Strength, hypertrophy, posture quality, progressive overload.</textarea></div><button class="btn btn-teal btn-full" id="saveRoutineBuilder">Save routine</button></div><div class="card span-2"><div class="section-head"><div><p class="stat-label white">Detailed setup</p><h2>Exercise, sets, reps, rest, tempo, type and intensity</h2></div></div><div class="grid grid-4"><select class="input" id="builderExercise">${exerciseLibrary.map(e=>`<option>${e.name}</option>`).join("")}</select><input class="input" id="builderSets" type="number" value="4"><input class="input" id="builderReps" value="8-10"><input class="input" id="builderRest" type="number" value="120"></div><div class="grid grid-4" style="margin-top:10px"><input class="input" id="builderTempo" value="3-1-1"><select class="input" id="builderType"><option>Straight sets</option><option>Superset</option><option>Circuit</option><option>Drop set</option><option>AMRAP</option></select><input class="input" id="builderRpe" value="RPE 8"><button class="btn" id="builderAdd">Add movement</button></div><div class="routine-list builder-list" id="builderList"></div></div></div></section>`;if(name==="options")panel.innerHTML=`<section class="panel-block"><div class="grid grid-3"><div class="card"><p class="stat-label white">Session defaults</p><div class="two-col"><div class="field"><label class="stat-label">Units</label><select class="input workout-setting" data-key="units"><option ${settings.units==='lbs'?'selected':''}>lbs</option><option ${settings.units==='kg'?'selected':''}>kg</option></select></div><div class="field"><label class="stat-label">Default rest seconds</label><input class="input workout-setting" data-key="defaultRest" type="number" value="${settings.defaultRest||120}"></div><div class="field"><label class="stat-label">Theme</label><select class="input workout-setting" data-key="sessionTheme"><option>Pro Glass</option><option>Minimal OLED</option><option>High Contrast</option></select></div><div class="field"><label class="stat-label">Density</label><select class="input workout-setting" data-key="densityMode"><option>Comfort</option><option>Compact</option></select></div></div><button class="btn btn-teal btn-full" id="saveWorkoutOptions">Save options</button></div><div class="card span-2"><p class="stat-label white">Tracking abilities</p><div class="toggle-grid">${[["autoProgression","Auto progression suggestions"],["warmupSets","Warm-up set planner"],["rpeTracking","RPE / RIR tracking"],["tempoTracking","Tempo tracking"],["plateCalculator","Plate calculator"],["soundCues","Rest sound cues"]].map(([k,l])=>`<label class="toggle-row"><span>${l}</span><input type="checkbox" class="workout-toggle" data-key="${k}" ${settings[k]!==false?'checked':''}></label>`).join("")}</div><div class="card-teal small muted" style="margin-top:14px">Saved locally and applied to new sessions.</div></div></div></section>`;if(name==="history")panel.innerHTML=`<section class="panel-block"><div class="section-head"><div><p class="stat-label">Recent Sessions</p><h2>Detailed workout log</h2></div><span class="tiny muted">${recent.length} shown</span></div><div class="stack">${recent.length?recent.map(w=>`<div class="list-item history-item"><div class="row"><div class="icon-box">${icons.calendar}</div><div><b>${esc(w.name||"Workout Session")}</b><p class="stat-label">${new Date(w.startedAt).toLocaleDateString(undefined,{weekday:"short",month:"short",day:"numeric"})} • ${w.totalSets||0} sets</p></div></div><div class="history-stats"><b>${money(w.totalVolume||0)}</b><span>volume</span></div></div>`).join(""):`<div class="glass empty-state"><p class="muted">No sessions yet. Start your first workout.</p></div>`}</div></section>`;bindPanel(name)}
  function bindPanel(name){if(name==="library"){const renderLib=()=>{const q=document.getElementById("exerciseSearch").value.toLowerCase();const m=document.getElementById("muscleFilter").value;const eq=document.getElementById("equipmentFilter").value;const lv=document.getElementById("levelFilter").value;const list=exerciseLibrary.filter(ex=>(m==="All muscles"||ex.muscle===m)&&(eq==="All equipment"||ex.equipment===eq)&&(lv==="All levels"||ex.level===lv)&&[ex.name,ex.aliases,ex.muscle,ex.equipment,ex.pattern,...ex.cues].join(" ").toLowerCase().includes(q));document.getElementById("exerciseLibrary").innerHTML=list.map(ex=>exerciseCard(ex)).join("")||`<div class="glass empty-state">No exercise matches.</div>`;bindExerciseButtons()};["exerciseSearch","muscleFilter","equipmentFilter","levelFilter"].forEach(id=>document.getElementById(id).oninput=renderLib);renderLib()}else bindExerciseButtons();if(name==="builder"){let draft=[];const draw=()=>document.getElementById("builderList").innerHTML=draft.map((x,i)=>`<div><span>${i+1}. ${esc(x.name)} <em>${esc(x.type)}</em></span><b>${esc(x.sets)}×${esc(x.reps)} • ${esc(x.rest)}s • ${esc(x.tempo)}</b></div>`).join("")||`<div><span class="muted">No movements added yet.</span><b></b></div>`;draw();document.getElementById("builderAdd").onclick=()=>{draft.push({name:builderExercise.value,sets:Number(builderSets.value||3),reps:builderReps.value,rest:Number(builderRest.value||120),tempo:builderTempo.value,type:builderType.value,rpe:builderRpe.value});draw()};document.getElementById("saveRoutineBuilder").onclick=()=>{if(!draft.length)draft=[{name:builderExercise.value,sets:Number(builderSets.value||3),reps:builderReps.value,rest:Number(builderRest.value||120),tempo:builderTempo.value,type:builderType.value,rpe:builderRpe.value}];state.routines.push({id:id(),name:routineName.value||"Custom Routine",description:routineDesc.value,exercises:draft});save();toast("Routine saved locally");drawPanel("routines")}}if(name==="options")document.getElementById("saveWorkoutOptions").onclick=()=>{state.workoutSettings=state.workoutSettings||{};document.querySelectorAll(".workout-setting").forEach(i=>state.workoutSettings[i.dataset.key]=i.type==="number"?Number(i.value):i.value);document.querySelectorAll(".workout-toggle").forEach(i=>state.workoutSettings[i.dataset.key]=i.checked);save();toast("Workout options saved")};document.querySelectorAll("[data-start-routine]").forEach(b=>b.onclick=()=>{const r=state.routines.find(x=>x.id===b.dataset.startRoutine);state.activeWorkout={startedAt:Date.now(),name:r.name,planned:routineItems(r),sets:[]};save();go("/workouts/active")});document.querySelectorAll("[data-delete-routine]").forEach(b=>b.onclick=()=>{state.routines=state.routines.filter(r=>r.id!==b.dataset.deleteRoutine);save();drawPanel("routines")});document.querySelectorAll("[data-edit-routine]").forEach(b=>b.onclick=()=>{const r=state.routines.find(x=>x.id===b.dataset.editRoutine);const n=prompt("Routine name",r.name);if(n!==null){r.name=n;r.description=prompt("Routine notes",r.description||"")||r.description;save();drawPanel("routines")}});document.querySelectorAll("[data-template]").forEach(b=>b.onclick=()=>{const t=workoutTemplates[Number(b.dataset.template)];state.routines.push({id:id(),name:t.name,description:t.goal,exercises:t.exercises.map(name=>{const e=exerciseByName(name);return{name,sets:e.defaultSets,reps:e.defaultReps,rest:e.defaultRest,tempo:e.tempo,type:"Straight sets",rpe:"RPE 8"}})});save();toast("Template saved as routine");drawPanel("routines")})}
  function bindExerciseButtons(){document.querySelectorAll("[data-add-exercise]").forEach(b=>b.onclick=()=>{const ex=exerciseLibrary.find(e=>e.id===b.dataset.addExercise);state.activeWorkout=state.activeWorkout||{startedAt:Date.now(),name:"Custom Workout",planned:[],sets:[]};state.activeWorkout.planned=state.activeWorkout.planned||[];state.activeWorkout.planned.push({name:ex.name,sets:ex.defaultSets,reps:ex.defaultReps,rest:ex.defaultRest,tempo:ex.tempo,type:"Straight sets",rpe:"RPE 8"});save();toast(`${ex.name} added to next session`)});document.querySelectorAll("[data-cache-guide]").forEach(b=>b.onclick=async()=>{const ex=exerciseLibrary.find(e=>e.id===b.dataset.cacheGuide);await cacheExerciseGuide(ex);toast(`${ex.name} guide saved offline`);drawPanel(document.querySelector("#workoutTabs .active")?.dataset.panel||"library")});document.querySelectorAll("[data-customize-ex]").forEach(b=>b.onclick=()=>{const ex=exerciseLibrary.find(e=>e.id===b.dataset.customizeEx);const sets=prompt("Default sets",ex.defaultSets);const reps=prompt("Default reps/time",ex.defaultReps);const rest=prompt("Default rest seconds",ex.defaultRest);if(sets&&reps&&rest){ex.defaultSets=Number(sets);ex.defaultReps=reps;ex.defaultRest=Number(rest);toast("Exercise defaults customized")}})}document.querySelectorAll("#workoutTabs .tab").forEach(t=>t.onclick=()=>drawPanel(t.dataset.panel));document.getElementById("startBlank").onclick=()=>{state.activeWorkout={startedAt:Date.now(),name:"Custom Workout",planned:[],sets:[]};save();go("/workouts/active")};document.getElementById("openBuilder").onclick=()=>drawPanel("builder");document.getElementById("addCustomExercise").onclick=()=>{const name=prompt("Custom exercise name");if(!name)return;exerciseLibrary.push({id:id(),name,aliases:"custom",muscle:prompt("Main muscle","Custom")||"Custom",secondary:"Custom",equipment:prompt("Equipment","Any")||"Any",level:"Custom",pattern:prompt("Movement pattern","Custom")||"Custom",mechanics:"Custom",defaultSets:3,defaultReps:"8-12",defaultRest:90,tempo:"2-1-2",progression:"Progress slowly while technique stays clean.",steps:["Set up safely.","Move with control.","Stop if pain appears."],cues:["Control","Brace","Full range"],mistakes:["Rushing","Poor posture","Too much load"],targets:["Custom"],animation:"push"});toast("Custom exercise added");drawPanel("library")};drawPanel("routines")}
  function renderActiveWorkout(){if(!state.activeWorkout)state.activeWorkout={startedAt:Date.now(),name:"Custom Workout",planned:[],sets:[]};state.activeWorkout.planned=state.activeWorkout.planned||[];state.activeWorkout.sets=state.activeWorkout.sets||[];save();const elapsed=()=>Math.floor((Date.now()-state.activeWorkout.startedAt)/1000);const planned=state.activeWorkout.planned;const selected=exerciseByName(planned[0]?.name||exercises[0]);view().innerHTML=`<section class="page active-workout-page"><header class="page-header"><div><p class="eyebrow">Live session</p><h1 class="display teal glow-text">${esc(state.activeWorkout.name||"Workout")}</h1><p id="timer" class="teal mono-timer">00:00</p></div><div class="row"><button class="btn" data-go="/workouts">Back</button><button class="btn btn-danger" id="finishWorkout">Finish</button></div></header><div class="grid grid-3"><div class="card span-2"><div class="section-head"><div><p class="stat-label white">Set logger</p><h2>Track weight, reps/time, RPE, rest, tempo and notes</h2></div><span class="badge" id="restBadge">Rest ready</span></div><div class="grid grid-4"><select class="input" id="exercise">${exerciseLibrary.map(e=>`<option ${e.name===selected.name?'selected':''}>${e.name}</option>`).join("")}</select><input class="input" id="weight" type="number" placeholder="Weight" value="100"><input class="input" id="reps" placeholder="Reps / sec" value="8"><input class="input" id="rpe" placeholder="RPE" value="8"></div><div class="grid grid-4" style="margin-top:10px"><input class="input" id="rest" type="number" placeholder="Rest sec" value="${state.workoutSettings?.defaultRest||selected.defaultRest}"><input class="input" id="tempo" placeholder="Tempo" value="${selected.tempo}"><input class="input" id="setNotes" placeholder="Notes"><button class="btn btn-teal" id="addSet">Add set</button></div><div class="stack" id="setList" style="margin-top:16px"></div></div><aside class="card posture-card"><p class="stat-label">Posture model</p><div id="postureBox">${exerciseCard(selected,true)}</div></aside><div class="card"><p class="stat-label">Live Volume</p><p class="big-number" id="liveVolume">0</p><p class="stat-label">${esc(state.workoutSettings?.units||"lbs")} total load</p><button class="btn btn-full" id="startRest">Start rest timer</button></div><div class="card"><p class="stat-label">Planned Work</p><div class="routine-list">${planned.length?planned.map((x,i)=>`<div><span>${i+1}. ${esc(x.name)}</span><b>${esc(x.sets||3)}×${esc(x.reps||"8-12")}</b></div>`).join(""):`<div><span class="muted">Blank workout. Add exercises as you go.</span><b></b></div>`}</div></div><div class="card"><p class="stat-label">Session tools</p><div class="toggle-grid"><button class="btn" id="addWarmups">Add warmups</button><button class="btn" id="plateCalc">Plate calc</button><button class="btn" id="copyLast">Copy last set</button><button class="btn" id="clearSession">Clear session</button></div></div></div></section>`;document.querySelectorAll("[data-go]").forEach(b=>b.addEventListener("click",()=>go(b.dataset.go)));let restInt=null;const draw=()=>{const sets=state.activeWorkout.sets;document.getElementById("setList").innerHTML=sets.map((s,i)=>`<div class="list-item"><div><b>${esc(s.exerciseName)}</b><p class="stat-label">SET ${i+1} • RPE ${esc(s.rpe||"-")} • ${esc(s.tempo||"-")} • REST ${esc(s.rest||0)}s</p>${s.notes?`<p class="small muted">${esc(s.notes)}</p>`:""}</div><b>${s.weight} × ${s.reps}</b></div>`).join("")||`<div class="glass empty-state"><p class="muted">No sets yet. Add your first working set.</p></div>`;document.getElementById("liveVolume").textContent=money(sets.reduce((a,s)=>a+(Number(s.weight)||0)*(Number(s.reps)||0),0))};const updatePosture=()=>{const ex=exerciseByName(document.getElementById("exercise").value);document.getElementById("postureBox").innerHTML=exerciseCard(ex,true);document.getElementById("rest").value=ex.defaultRest;document.getElementById("tempo").value=ex.tempo};draw();document.getElementById("exercise").onchange=updatePosture;document.getElementById("addSet").onclick=()=>{state.activeWorkout.sets.push({exerciseName:exercise.value,weight:Number(weight.value||0),reps:Number(reps.value||0),rpe:rpe.value,rest:Number(rest.value||0),tempo:tempo.value,notes:setNotes.value,createdAt:new Date().toISOString()});save();draw();startRestTimer(Number(rest.value||0))};function startRestTimer(sec){clearInterval(restInt);let left=sec;const badge=document.getElementById("restBadge");if(!left){badge.textContent="Rest ready";return}badge.textContent=`Rest ${left}s`;restInt=setInterval(()=>{left--;badge.textContent=left>0?`Rest ${left}s`:"Rest complete";if(left<=0)clearInterval(restInt)},1000)}document.getElementById("startRest").onclick=()=>startRestTimer(Number(rest.value||state.workoutSettings?.defaultRest||120));document.getElementById("copyLast").onclick=()=>{const last=state.activeWorkout.sets.at(-1);if(last){state.activeWorkout.sets.push({...last,createdAt:new Date().toISOString()});save();draw()}};document.getElementById("addWarmups").onclick=()=>{state.activeWorkout.sets.push({exerciseName:exercise.value,weight:45,reps:10,rpe:"Warmup",rest:60,tempo:"controlled",notes:"Auto warm-up set"});save();draw()};document.getElementById("plateCalc").onclick=()=>toast("Plate calculator option saved; detailed calculator can be expanded next.");document.getElementById("clearSession").onclick=()=>{state.activeWorkout.sets=[];save();draw()};document.getElementById("finishWorkout").onclick=()=>{const sets=state.activeWorkout.sets;const totalVolume=sets.reduce((a,s)=>a+(Number(s.weight)||0)*(Number(s.reps)||0),0);state.workouts.push({id:id(),name:state.activeWorkout.name||"Workout Session",startedAt:new Date(state.activeWorkout.startedAt).toISOString(),finishedAt:new Date().toISOString(),totalVolume,totalSets:sets.length,sets});state.activeWorkout=null;save();toast("Workout saved locally");go("/workouts")};const tick=setInterval(()=>{const e=elapsed();document.getElementById("timer").textContent=`${String(Math.floor(e/60)).padStart(2,"0")}:${String(e%60).padStart(2,"0")}`},1000);cleanup=()=>{clearInterval(restInt);clearInterval(tick)}}
  function renderNutrition(){const s=summary();const logs=todayLogs();const remaining=Math.max(0,s.calorieGoal-s.todayCalories);const calPct=Math.min(100,s.todayCalories/s.calorieGoal*100);const meals=["breakfast","lunch","dinner","snack"];view().innerHTML=`<section class="page">${header("Fuel protocol","Nutrition")}<div class="grid grid-3"><div class="card" style="display:grid;place-items:center"><p class="stat-label" style="justify-self:start">Daily Calories</p><div class="macro-ring" style="--pct:${calPct}%"><div><b style="font-size:30px">${money(s.todayCalories)}</b><p class="stat-label">/ ${money(s.calorieGoal)}</p></div></div><div class="row" style="width:100%;margin-top:16px"><div><b class="teal">${money(remaining)}</b><p class="stat-label">Remaining</p></div><div style="text-align:right"><b class="green">${Math.round(calPct)}%</b><p class="stat-label">Complete</p></div></div></div><div class="card"><p class="stat-label" style="margin-bottom:20px">Macronutrients</p>${muscleBars([{label:"PROTEIN",pct:Math.min(100,s.todayProtein/state.settings.proteinGoal*100),color:TEAL},{label:"CARBS",pct:Math.min(100,logs.reduce((a,l)=>a+l.carbs,0)/state.settings.carbsGoal*100),color:PURPLE},{label:"FATS",pct:Math.min(100,logs.reduce((a,l)=>a+l.fat,0)/state.settings.fatGoal*100),color:GREEN},{label:"FIBER",pct:51,color:ORANGE}].map(x=>({...x,pct:Math.round(x.pct)})))}</div><div class="card"><div class="row" style="margin-bottom:14px"><p class="stat-label">Daily Habits</p><b class="teal small">${s.habitsCompletedToday}/${s.totalHabits}</b></div><div class="stack">${state.habits.map(h=>{const done=state.habitLogs.some(l=>l.habitId===h.id&&l.date===dateISO()&&l.completed);return`<button class="list-item habit-btn" data-id="${h.id}" style="text-align:left"><span class="icon-box">${done?icons.check:icons.plus}</span><span style="flex:1"><b>${esc(h.name)}</b><p class="stat-label">TARGET ${h.targetValue} ${h.unit}</p></span></button>`}).join("")}</div></div><div class="span-3"><div class="row" style="margin-bottom:12px"><p class="stat-label">Today's Meals</p><button class="btn btn-teal" id="logFoodBtn">Log Food</button></div><div class="grid grid-4">${meals.map(m=>{const cat=logs.filter(l=>l.mealCategory===m);return`<div class="card meal-card"><p class="stat-label">${m}</p><h2 style="margin-top:10px">${money(cat.reduce((a,l)=>a+l.calories,0))}</h2><p class="stat-label">KCAL</p><div class="stack" style="gap:4px;margin-top:12px">${cat.slice(0,3).map(l=>`<p class="tiny muted">${esc(l.foodName)}</p>`).join("")||`<p class="tiny muted"><i>Empty</i></p>`}</div></div>`}).join("")}</div></div></div><div class="card" id="foodForm" style="display:none;margin-top:16px"><div class="grid grid-4"><select class="input" id="foodSelect">${foods.map(f=>`<option value="${f.id}">${f.name}</option>`).join("")}</select><select class="input" id="mealSelect">${meals.map(m=>`<option>${m}</option>`).join("")}</select><input class="input" id="servings" type="number" step="0.25" value="1"><button class="btn btn-teal" id="saveFood">Save Food</button></div></div></section>`;document.querySelectorAll(".habit-btn").forEach(b=>b.onclick=()=>{const h=b.dataset.id;const existing=state.habitLogs.find(l=>l.habitId===h&&l.date===dateISO());if(existing)existing.completed=!existing.completed;else state.habitLogs.push({id:id(),habitId:h,date:dateISO(),completed:true});save();renderNutrition()});document.getElementById("logFoodBtn").onclick=()=>document.getElementById("foodForm").style.display="block";document.getElementById("saveFood").onclick=()=>{state.nutritionLogs.push(makeFoodLog(Number(document.getElementById("foodSelect").value),document.getElementById("mealSelect").value,Number(document.getElementById("servings").value||1)));save();toast("Food logged locally");renderNutrition()}}
function renderRecovery(){view().innerHTML=`<section class="page">${header("CNS recovery","Recovery")}<div class="grid grid-3"><div class="card"><div class="row"><p class="stat-label">Box Breathing</p><span class="muted">${icons.wind}</span></div><div class="breath-orb" id="breath"><div class="breath-glow"></div><div class="breath-center"><div><b id="phase" class="teal">TAP TO START</b><p class="stat-label" id="phaseTime">4s</p></div></div></div><div class="row"><div><p class="stat-label">Elapsed</p><b id="elapsed">0:00</b></div><div style="text-align:right"><p class="stat-label">Cycles</p><b class="teal" id="cycles">0</b></div></div></div><div class="card"><p class="stat-label" style="margin-bottom:20px">Recovery Metrics</p>${muscleBars([{label:"SLEEP QUALITY",pct:83,color:TEAL},{label:"HRV SCORE",pct:68,color:GREEN},{label:"CNS READINESS",pct:82,color:TEAL},{label:"SORENESS LEVEL",pct:30,color:ORANGE},{label:"HYDRATION",pct:70,color:PURPLE}])}</div><div class="card"><p class="stat-label" style="margin-bottom:20px">Muscle Recovery Status</p>${muscleBars([{label:"CHEST",pct:68,color:ORANGE},{label:"BACK",pct:92,color:GREEN},{label:"SHOULDERS",pct:55,color:ORANGE},{label:"LEGS",pct:85,color:TEAL},{label:"ARMS",pct:78,color:TEAL},{label:"CORE",pct:95,color:GREEN}])}</div></div></section>`;let running=false,sec=0,idx=0;const phases=["INHALE","HOLD","EXHALE","REST"];const colors=[TEAL,PURPLE,ORANGE,GREEN];let int=null,phaseInt=null;const setPhase=()=>{document.getElementById("phase").textContent=phases[idx];document.getElementById("phase").style.color=colors[idx];document.querySelector(".breath-glow").style.background=colors[idx];document.querySelector(".breath-center").style.borderColor=colors[idx];idx=(idx+1)%phases.length};document.getElementById("breath").onclick=()=>{running=!running;document.getElementById("breath").classList.toggle("active",running);clearInterval(int);clearInterval(phaseInt);if(running){setPhase();int=setInterval(()=>{sec++;document.getElementById("elapsed").textContent=`${Math.floor(sec/60)}:${String(sec%60).padStart(2,"0")}`;document.getElementById("cycles").textContent=Math.floor(sec/16)},1000);phaseInt=setInterval(setPhase,4000)}else{document.getElementById("phase").textContent="TAP TO START"}};cleanup=()=>{clearInterval(int);clearInterval(phaseInt)}}
function renderAnalytics(){const s=summary();view().innerHTML=`<section class="page">${header("Performance intel","Analytics")}<div class="grid grid-3"><div class="card span-2"><div class="row"><div><p class="stat-label">Weekly Training Volume</p><p class="tiny muted">LBS / WEEK</p></div><span class="badge">Live</span></div>${barChart(s.weeklyVolume)}</div><div class="card"><p class="stat-label" style="margin-bottom:18px">Muscle Saturation</p>${muscleBars([{label:"CHEST (PEC MAJOR)",pct:88,color:ORANGE},{label:"DELTOIDS",pct:34,color:TEAL},{label:"TRICEPS",pct:72,color:TEAL},{label:"QUADRICEPS",pct:91,color:ORANGE},{label:"LATS",pct:55,color:TEAL},{label:"HAMSTRINGS",pct:61,color:GREEN}])}</div><div class="span-3"><p class="stat-label" style="margin-bottom:12px">AI-Derived Insights</p><div class="grid grid-3">${[{t:"Strong Correlation",b:"Days with 7+ hours of sleep show a 15% increase in average lifting volume. Protect your sleep window.",c:TEAL},{t:"Recovery Note",b:"Your chest recovery is lagging. Consider an extra rest day before the next push session to maximize gains.",c:ORANGE},{t:"Habit Trend",b:"Protein goal hit 6 days in a row. Maintaining consistent nutrition directly supports muscle protein synthesis.",c:GREEN}].map(x=>`<div class="card" style="background:${x.c}10;border-color:${x.c}35"><p class="stat-label" style="color:${x.c}">${x.t}</p><p class="small muted" style="margin-top:10px;line-height:1.6">${x.b}</p></div>`).join("")}</div></div></div></section>`}
function renderAI(){view().innerHTML=`<section class="page chat-page"><div class="chat-shell"><div class="chat-head"><div class="row"><div class="row"><div class="icon-box">${icons.ai}</div><div><p class="stat-label">AI Super-Coach</p><h2 class="display" style="font-size:28px">OMNI Coach</h2></div></div><div class="row"><span style="width:8px;height:8px;border-radius:50%;background:${navigator.onLine?GREEN:ORANGE};display:block"></span><span class="stat-label ${navigator.onLine?"green":"orange"}">${navigator.onLine?"Online":"Offline"}</span></div></div></div><div class="messages" id="messages"></div><div class="chat-input"><div class="row"><input class="input" id="aiInput" placeholder="Ask OMNI anything about your performance..."><button class="btn btn-teal" id="sendAI">Send</button></div></div></div></section>`;drawMessages();document.getElementById("sendAI").onclick=sendAI;document.getElementById("aiInput").onkeydown=e=>{if(e.key==="Enter")sendAI()}}
function drawMessages(typing=false){const box=document.getElementById("messages");const suggestions=["What's my optimal training volume today?","Analyze my sleep and bench press correlation","Suggest a deload week plan","What should I eat before today's session?"];box.innerHTML=state.aiMessages.map(m=>`<div class="msg ${m.role}"><div class="icon-box">${m.role==="assistant"?icons.ai:"U"}</div><div class="bubble">${esc(m.content)}</div></div>`).join("")+(typing?`<div class="msg assistant"><div class="icon-box">${icons.ai}</div><div class="bubble typing"><span></span><span></span><span></span></div></div>`:state.aiMessages.length===1?`<div class="suggestions"><p class="stat-label">Suggested Queries</p>${suggestions.map(s=>`<button class="btn" data-suggest="${esc(s)}" style="text-align:left;text-transform:none;letter-spacing:0">${esc(s)}</button>`).join("")}</div>`:"");box.scrollTop=box.scrollHeight;document.querySelectorAll("[data-suggest]").forEach(b=>b.onclick=()=>sendAI(b.dataset.suggest))}
async function sendAI(text){const input=document.getElementById("aiInput");const prompt=(text||input.value).trim();if(!prompt)return;state.aiMessages.push({role:"user",content:prompt});input.value="";save();drawMessages(true);let answer="";if(state.settings.apiKey&&navigator.onLine){try{const s=summary();const context=`Readiness ${s.readinessScore}%, calories ${s.todayCalories}/${s.calorieGoal}, protein ${s.todayProtein}g, workout streak ${s.currentStreak} days, habit consistency ${(s.habitConsistency*100).toFixed(1)}%.`;const res=await fetch("https://api.openai.com/v1/chat/completions",{method:"POST",headers:{"Content-Type":"application/json","Authorization":`Bearer ${state.settings.apiKey}`},body:JSON.stringify({model:state.settings.model||"gpt-4o",messages:[{role:"system",content:`You are OMNI, a concise elite fitness coach. Use this local athlete context: ${context}`},...state.aiMessages.slice(-8)],temperature:.5})});if(!res.ok)throw new Error(await res.text());const data=await res.json();answer=data.choices?.[0]?.message?.content||"I could not read a response from the AI service."}catch(e){answer="AI internet call failed. Your offline app still works; check your API key, connection, or model setting."}}else{answer="AI requires internet and an OpenAI API key saved in Settings. Offline mode is active, so I can still give a local guidance preview: readiness is strong, keep protein high, and avoid adding heavy chest volume if soreness is above normal."}state.aiMessages.push({role:"assistant",content:answer});save();drawMessages(false)}
function renderSettings(){const s=state.settings;view().innerHTML=`<section class="page" style="max-width:900px">${header("System config","Settings")}<div class="stack"><div class="card"><p class="stat-label white">Profile & Body</p><div class="two-col" style="margin-top:16px">${field("DISPLAY NAME","displayName",s.displayName,"text")}${field("HEIGHT (CM)","height",s.height,"number")}${field("BODY WEIGHT (KG)","weight",s.weight,"number")}${field("AGE","age",s.age,"number")}</div></div><div class="card"><p class="stat-label white">AI Configuration</p><div class="field" style="margin-top:16px"><label class="stat-label">OPENAI API KEY (BYOK)</label><input class="input" id="apiKey" type="password" placeholder="sk-..." value="${esc(s.apiKey)}"></div><div class="card-teal small muted" style="margin:12px 0">Stored locally in this browser via localStorage. AI is the only feature that needs internet.</div><div class="field"><label class="stat-label">AI MODEL</label><select class="input" id="model"><option ${s.model==="gpt-4o"?"selected":""}>gpt-4o</option><option ${s.model==="gpt-4-turbo"?"selected":""}>gpt-4-turbo</option><option ${s.model==="gpt-3.5-turbo"?"selected":""}>gpt-3.5-turbo</option></select></div></div><div class="card"><p class="stat-label white">Nutrition Targets</p><div class="grid grid-4" style="margin-top:16px">${field("TRAINING CALORIES","trainingCalories",s.trainingCalories,"number")}${field("REST CALORIES","restCalories",s.restCalories,"number")}${field("PROTEIN (G)","proteinGoal",s.proteinGoal,"number")}${field("CARBS (G)","carbsGoal",s.carbsGoal,"number")}</div></div><div class="card"><p class="stat-label white">Data Management</p><div class="grid grid-3" style="margin-top:16px"><button class="btn btn-teal" id="exportData">Export JSON</button><button class="btn" id="importData">Import Backup</button><button class="btn btn-danger" id="clearData">Clear All Data</button><input class="file-input" id="fileInput" type="file" accept="application/json"></div></div><button class="btn btn-teal btn-full" id="saveSettings">Save Configuration</button></div></section>`;document.getElementById("saveSettings").onclick=saveSettings;document.getElementById("exportData").onclick=exportData;document.getElementById("importData").onclick=()=>document.getElementById("fileInput").click();document.getElementById("fileInput").onchange=importData;document.getElementById("clearData").onclick=()=>{if(confirm("Clear all local OMNI data?")){localStorage.removeItem(STORE_KEY);state=structuredClone(defaultState);toast("Local data cleared");shell()}}}
function field(label,key,value,type){return`<div class="field"><label class="stat-label">${label}</label><input class="input setting" data-key="${key}" type="${type}" value="${esc(value)}"></div>`}
function saveSettings(){document.querySelectorAll(".setting").forEach(i=>state.settings[i.dataset.key]=i.type==="number"?Number(i.value):i.value);state.settings.apiKey=document.getElementById("apiKey").value;state.settings.model=document.getElementById("model").value;save();toast("Configuration saved locally")}
function exportData(){const blob=new Blob([JSON.stringify(state,null,2)],{type:"application/json"});const a=document.createElement("a");a.href=URL.createObjectURL(blob);a.download="omni-offline-backup.json";a.click();URL.revokeObjectURL(a.href)}
function importData(e){const file=e.target.files[0];if(!file)return;const reader=new FileReader();reader.onload=()=>{try{state=merge(defaultState,JSON.parse(reader.result));save();toast("Backup imported");shell()}catch{toast("Invalid backup file")}};reader.readAsText(file)}
function view(){return document.getElementById("view")}
function toast(msg){const t=document.createElement("div");t.className="toast";t.textContent=msg;document.body.appendChild(t);setTimeout(()=>t.remove(),2600)}
window.addEventListener("hashchange",shell);
shell();